+const std = @import("std");
+const lora_trainer = @import("lora_trainer.zig");
+const logger = @import("logger.zig");
+
+pub fn spawnBackgroundTraining(
+    allocator: std.mem.Allocator,
+    model_path: []const u8,
+    model_hash: u64,
+) !void {
+    // Fork a background process to avoid blocking inference
+    const pid = try std.posix.fork();
+
+    if (pid == 0) {
+        // Child process: run training
+        trainInBackground(allocator, model_path, model_hash) catch |err| {
+            logger.err("Background training failed: {}", .{err});
+            std.process.exit(1);
+        };
+        std.process.exit(0);
+    }
+
+    // Parent: continue immediately
+    logger.info("Background training started (pid: {d})", .{pid});
+}
+
+fn trainInBackground(
+    allocator: std.mem.Allocator,
+    model_path: []const u8,
+    model_hash: u64,
+) !void {
+    const home = std.posix.getenv("HOME") orelse return error.NoHomeDir;
+
+    // Collect all conversation JSONL files
+    const conv_dir = try std.fmt.allocPrint(allocator,
+        "{s}/.cache/zell/conversations/{x}", .{ home, model_hash });
+    defer allocator.free(conv_dir);
+
+    // Merge all JSONL files into training data
+    const lora_dir = try std.fmt.allocPrint(allocator,
+        "{s}/.cache/zell/lora", .{home});
+    defer allocator.free(lora_dir);
+
+    // Ensure lora directory exists
+    try std.fs.cwd().makePath(lora_dir);
+
+    const training_data = try std.fmt.allocPrint(allocator,
+        "{s}/{x}_auto_training.jsonl", .{ lora_dir, model_hash });
+    defer allocator.free(training_data);
+
+    try mergeConversationFiles(allocator, conv_dir, training_data);
+
+    // Output adapter path
+    const adapter_path = try std.fmt.allocPrint(allocator,
+        "{s}/{x}_auto.lora", .{ lora_dir, model_hash });
+    defer allocator.free(adapter_path);
+
+    // Train using existing lora_trainer
+    logger.info("Training LoRA adapter from conversations...", .{});
+    const config = lora_trainer.TrainingConfig{
+        .model_path = model_path,
+        .output_path = adapter_path,
+        .data_jsonl_path = training_data,
+        .epochs = 3,
+        .rank = 16,
+        .learning_rate = 0.0001,
+        .batch_size = 32,
+    };
+
+    try lora_trainer.train(allocator, config);
+
+    // Clean up merged training file (keep original conversations)
+    std.fs.cwd().deleteFile(training_data) catch {};
+
+    logger.info("✓ Auto-trained adapter saved: {s}", .{adapter_path});
+}
+
+fn mergeConversationFiles(
+    allocator: std.mem.Allocator,
+    conv_dir: []const u8,
+    output_path: []const u8,
+) !void {
+    var dir = try std.fs.cwd().openDir(conv_dir, .{ .iterate = true });
+    defer dir.close();
+
+    const output = try std.fs.cwd().createFile(output_path, .{});
+    defer output.close();
+
+    var iter = dir.iterate();
+    while (try iter.next()) |entry| {
+        if (entry.kind != .file) continue;
+        if (!std.mem.endsWith(u8, entry.name, ".jsonl")) continue;
+
+        const file = try dir.openFile(entry.name, .{});
+        defer file.close();
+
+        const content = try file.readToEndAlloc(allocator, 10 * 1024 * 1024);
+        defer allocator.free(content);
+
+        // Transform conversation format to training format
+        // Each JSONL line has: {"timestamp":..,"model":..,"prompt":"..","response":"..","tokens":..}
+        // We need to convert to: {"text": "prompt\nresponse"}
+        var lines = std.mem.splitScalar(u8, content, '\n');
+        while (lines.next()) |line| {
+            if (line.len == 0) continue;
+
+            // Parse JSON to extract prompt and response
+            const parsed = std.json.parseFromSlice(
+                struct {
+                    prompt: []const u8,
+                    response: []const u8,
+                },
+                allocator,
+                line,
+                .{},
+            ) catch continue;
+            defer parsed.deinit();
+
+            // Format as training example
+            const training_line = try std.fmt.allocPrint(allocator,
+                "{{\"text\": \"{s}\\n{s}\"}}\n",
+                .{ parsed.value.prompt, parsed.value.response },
+            );
+            defer allocator.free(training_line);
+
+            try output.writeAll(training_line);
+        }
+    }
+}

