+const std = @import("std");
+
+pub const ConversationEntry = struct {
+    timestamp: i64,
+    model_hash: u64,
+    prompt: []const u8,
+    response: []const u8,
+    tokens_used: u32,
+
+    pub fn toJsonl(self: *const ConversationEntry, allocator: std.mem.Allocator) ![]u8 {
+        // Escape JSON strings
+        const prompt_escaped = try escapeJson(allocator, self.prompt);
+        defer allocator.free(prompt_escaped);
+        const response_escaped = try escapeJson(allocator, self.response);
+        defer allocator.free(response_escaped);
+
+        return try std.fmt.allocPrint(allocator,
+            "{{\"timestamp\":{d},\"model\":\"{x}\",\"prompt\":\"{s}\",\"response\":\"{s}\",\"tokens\":{d}}}\n",
+            .{ self.timestamp, self.model_hash, prompt_escaped, response_escaped, self.tokens_used },
+        );
+    }
+};
+
+pub const ConversationLogger = struct {
+    allocator: std.mem.Allocator,
+    model_hash: u64,
+    log_path: []const u8,
+
+    pub fn init(allocator: std.mem.Allocator, model_hash: u64) !ConversationLogger {
+        // Create log directory
+        const home = std.posix.getenv("HOME") orelse return error.NoHomeDir;
+        const log_dir = try std.fmt.allocPrint(allocator,
+            "{s}/.cache/zell/conversations/{x}", .{ home, model_hash });
+        defer allocator.free(log_dir);
+
+        try std.fs.cwd().makePath(log_dir);
+
+        // Log path: ~/.cache/zell/conversations/{model_hash}/YYYY-MM-DD.jsonl
+        const now = std.time.timestamp();
+        const date_str = try formatDate(allocator, now);
+        defer allocator.free(date_str);
+
+        const log_path = try std.fmt.allocPrint(allocator,
+            "{s}/.cache/zell/conversations/{x}/{s}.jsonl", .{ home, model_hash, date_str });
+
+        return ConversationLogger{
+            .allocator = allocator,
+            .model_hash = model_hash,
+            .log_path = log_path,
+        };
+    }
+
+    pub fn deinit(self: *ConversationLogger) void {
+        self.allocator.free(self.log_path);
+    }
+
+    pub fn log(self: *ConversationLogger, prompt: []const u8, response: []const u8, tokens: u32) !void {
+        const entry = ConversationEntry{
+            .timestamp = std.time.timestamp(),
+            .model_hash = self.model_hash,
+            .prompt = prompt,
+            .response = response,
+            .tokens_used = tokens,
+        };
+
+        const jsonl = try entry.toJsonl(self.allocator);
+        defer self.allocator.free(jsonl);
+
+        // Append to daily log file
+        const file = try std.fs.cwd().createFile(self.log_path, .{
+            .read = false,
+            .truncate = false,
+        });
+        defer file.close();
+
+        // Seek to end for appending
+        try file.seekFromEnd(0);
+        try file.writeAll(jsonl);
+    }
+
+    pub fn shouldTriggerTraining(self: *ConversationLogger) !bool {
+        // Check conversation count in directory
+        const dir_path = std.fs.path.dirname(self.log_path) orelse return false;
+        var dir = try std.fs.cwd().openDir(dir_path, .{ .iterate = true });
+        defer dir.close();
+
+        var total_lines: usize = 0;
+        var iter = dir.iterate();
+        while (try iter.next()) |entry| {
+            if (entry.kind != .file) continue;
+            if (!std.mem.endsWith(u8, entry.name, ".jsonl")) continue;
+
+            const file = try dir.openFile(entry.name, .{});
+            defer file.close();
+
+            const content = try file.readToEndAlloc(self.allocator, 10 * 1024 * 1024);
+            defer self.allocator.free(content);
+
+            // Count lines
+            var lines = std.mem.splitScalar(u8, content, '\n');
+            while (lines.next()) |line| {
+                if (line.len > 0) total_lines += 1;
+            }
+        }
+
+        // Trigger training every 100 conversations
+        return total_lines >= 100;
+    }
+};
+
+fn formatDate(allocator: std.mem.Allocator, timestamp: i64) ![]u8 {
+    // Calculate days since Unix epoch
+    const days = @divFloor(timestamp, 86400);
+    return try std.fmt.allocPrint(allocator, "{d}", .{days});
+}
+
+fn escapeJson(allocator: std.mem.Allocator, s: []const u8) ![]u8 {
+    // Count characters that need escaping
+    var escaped_len: usize = 0;
+    for (s) |c| {
+        escaped_len += switch (c) {
+            '"', '\\', '\n', '\r', '\t' => 2,
+            else => 1,
+        };
+    }
+
+    if (escaped_len == s.len) {
+        // No escaping needed
+        return try allocator.dupe(u8, s);
+    }
+
+    // Allocate and build escaped string
+    var result = try allocator.alloc(u8, escaped_len);
+    var i: usize = 0;
+    for (s) |c| {
+        switch (c) {
+            '"' => {
+                result[i] = '\\';
+                result[i + 1] = '"';
+                i += 2;
+            },
+            '\\' => {
+                result[i] = '\\';
+                result[i + 1] = '\\';
+                i += 2;
+            },
+            '\n' => {
+                result[i] = '\\';
+                result[i + 1] = 'n';
+                i += 2;
+            },
+            '\r' => {
+                result[i] = '\\';
+                result[i + 1] = 'r';
+                i += 2;
+            },
+            '\t' => {
+                result[i] = '\\';
+                result[i + 1] = 't';
+                i += 2;
+            },
+            else => {
+                result[i] = c;
+                i += 1;
+            },
+        }
+    }
+
+    return result;
+}

