+) !void {
+    // Create optimizer parameters callback
+    const GetOptPars = struct {
+        fn callback(userdata_: ?*anyopaque) callconv(.c) c.ggml_opt_optimizer_params {
+            const opt_params = @as(*const OptParams, @ptrCast(@alignCast(userdata_)));
+
+            var result: c.ggml_opt_optimizer_params = undefined;
+            if (opt_params.optimizer_type == .adamw) {
+                result.adamw.alpha = opt_params.learning_rate;
+                result.adamw.beta1 = opt_params.beta1;
+                result.adamw.beta2 = opt_params.beta2;
+                result.adamw.eps = opt_params.eps;
+                result.adamw.wd = opt_params.weight_decay;
+            } else {
+                result.sgd.alpha = opt_params.learning_rate;
+                result.sgd.wd = opt_params.weight_decay;
+            }
+            return result;
+        }
+    };
+
+    const lopt_params: c.llama_opt_params = .{
+        .n_ctx_train = params.n_ctx_train,
+        .param_filter = c.llama_opt_param_filter_all,
+        .param_filter_ud = null,
+        .get_opt_pars = GetOptPars.callback,
+        .get_opt_pars_ud = @constCast(@ptrCast(&params)),
+        .optimizer_type = @intFromEnum(params.optimizer_type),
+    };
