+// ============================================================================
+// Dataset API
+// ============================================================================
+
+/// Create a training dataset from token array
+/// This creates a simple dataset for language modeling where each example
+/// consists of `stride` tokens as input and the next token as the label
+pub fn createDataset(
+    allocator: std.mem.Allocator,
+    tokens: []const c.llama_token,
+    stride: usize,
+) !Dataset {
+    _ = allocator;
+
+    // For language modeling, we create sliding windows of tokens
+    const n_tokens = tokens.len;
+    if (n_tokens < stride + 1) {
+        return error.InsufficientTokens;
+    }
+
+    // Number of training examples = tokens / stride (non-overlapping windows)
+    const n_examples = n_tokens / stride;
+    if (n_examples == 0) {
+        return error.InsufficientTokens;
+    }
+
+    // Create dataset using GGML API
+    // For language modeling: input is stride tokens, output is 1 token (next token)
+    const dataset_maybe = c.ggml_opt_dataset_init(
+        c.GGML_TYPE_I32, // data type (tokens are i32)
+        c.GGML_TYPE_I32, // label type (next token is also i32)
+        @intCast(stride), // elements per datapoint (context size)
+        1, // elements per label (predicting 1 next token)
+        @intCast(n_examples), // total number of datapoints
+        @intCast(n_examples), // shard size (use all data in one shard)
+    );
+
+    const dataset = dataset_maybe orelse return error.FailedToCreateDataset;
+
+    // Get the data and label tensors from the dataset
+    const data_tensor_maybe = c.ggml_opt_dataset_data(dataset);
+    const label_tensor_maybe = c.ggml_opt_dataset_labels(dataset);
+
+    const data_tensor = data_tensor_maybe orelse {
+        c.ggml_opt_dataset_free(dataset);
+        return error.FailedToCreateDataset;
+    };
+
+    const label_tensor = label_tensor_maybe orelse {
+        c.ggml_opt_dataset_free(dataset);
+        return error.FailedToCreateDataset;
+    };
+
+    // Fill the dataset with token windows
+    // data_tensor is shape [stride, n_examples]
+    // label_tensor is shape [1, n_examples]
+    const data_ptr = @as([*]c.llama_token, @ptrCast(@alignCast(data_tensor.*.data)));
+    const label_ptr = @as([*]c.llama_token, @ptrCast(@alignCast(label_tensor.*.data)));
+
+    var i: usize = 0;
+    while (i < n_examples) : (i += 1) {
+        const start_idx = i * stride;
+
+        // Copy input tokens (context window)
+        const data_offset = i * stride;
+        for (0..stride) |j| {
+            if (start_idx + j < n_tokens) {
+                data_ptr[data_offset + j] = tokens[start_idx + j];
+            }
+        }
+
+        // Copy label token (next token after context)
+        if (start_idx + stride < n_tokens) {
+            label_ptr[i] = tokens[start_idx + stride];
+        }
+    }
+
+    return dataset;
+}
+
+/// Free a training dataset
+pub fn freeDataset(dataset: Dataset) void {
+    c.ggml_opt_dataset_free(dataset);
+}
+
+/// Get number of datapoints in dataset
+pub fn datasetSize(dataset: Dataset) i64 {
+    return c.ggml_opt_dataset_ndata(dataset);
+}
