+const std = @import("std");
+const llama = @import("llama.zig");
+const logger = @import("logger.zig");
+
+/// Training configuration
+pub const TrainingConfig = struct {
+    model_path: []const u8,
+    output_path: []const u8,
+
+    // Training data (one of these must be set)
+    data_jsonl_path: ?[]const u8 = null,
+    data_from_repo: ?[]const u8 = null,
+
+    // Hyperparameters
+    epochs: u32 = 3,
+    learning_rate: f32 = 0.0001,
+    rank: u32 = 16, // LoRA rank
+    alpha: f32 = 32.0, // LoRA alpha
+    batch_size: u32 = 32,
+    ctx_size: u32 = 2048,
+    weight_decay: f32 = 0.0,
+
+    // Optimizer
+    optimizer: llama.OptimizerType = .adamw,
+
+    // Validation split
+    val_split: f32 = 0.1, // 10% for validation
+};
+
+/// Training example
+pub const TrainingExample = struct {
+    text: []const u8,
+
+    pub fn deinit(self: *TrainingExample, allocator: std.mem.Allocator) void {
+        allocator.free(self.text);
+    }
+};
+
+/// Train a LoRA adapter
+pub fn train(
+    allocator: std.mem.Allocator,
+    config: TrainingConfig,
+) !void {
+    logger.info("Starting LoRA training...", .{});
+    logger.info("Model: {s}", .{config.model_path});
+    logger.info("Output: {s}", .{config.output_path});
+    logger.info("Epochs: {d}, LR: {d}, Rank: {d}, Alpha: {d}", .{
+        config.epochs,
+        config.learning_rate,
+        config.rank,
+        config.alpha,
+    });
+
+    // Step 1: Load training data
+    var examples = try std.ArrayList(TrainingExample).initCapacity(allocator, 0);
+    defer {
+        for (examples.items) |*ex| ex.deinit(allocator);
+        examples.deinit(allocator);
+    }
+
+    if (config.data_from_repo) |repo_path| {
+        logger.info("Learning from repository: {s}", .{repo_path});
+        try learnFromRepo(allocator, repo_path, &examples);
+    } else if (config.data_jsonl_path) |jsonl_path| {
+        logger.info("Loading training data from: {s}", .{jsonl_path});
+        try loadJsonlData(allocator, jsonl_path, &examples);
+    } else {
+        return error.NoTrainingDataProvided;
+    }
+
+    logger.info("Loaded {d} training examples", .{examples.items.len});
+
+    if (examples.items.len == 0) {
+        return error.NoTrainingExamples;
+    }
+
+    // Step 2: Load model
+    logger.info("Loading model...", .{});
+    var model = try llama.Model.load(config.model_path, .{
+        .n_gpu_layers = 99,
+    });
+    defer model.deinit();
+
+    // Step 3: Create context
+    logger.info("Creating training context...", .{});
+    var ctx = try llama.Context.init(&model, .{
+        .n_ctx = config.ctx_size,
+        .n_batch = config.batch_size,
+    });
+    defer ctx.deinit();
+
+    // Step 4: Tokenize training data
+    logger.info("Tokenizing training data...", .{});
+    var all_tokens = try std.ArrayList(i32).initCapacity(allocator, 0);
+    defer all_tokens.deinit(allocator);
+
+    for (examples.items) |example| {
+        const tokens = try llama.tokenize(&model, example.text, true);
+        defer allocator.free(tokens);
+
+        try all_tokens.appendSlice(allocator, tokens);
+    }
+
+    logger.info("Total tokens: {d}", .{all_tokens.items.len});
+
+    // Step 5: Create dataset from tokens
+    logger.info("Creating training dataset...", .{});
+    const stride = config.ctx_size; // Use context size as stride for language modeling
+    const dataset = try llama.createDataset(allocator, all_tokens.items, stride);
+    defer llama.freeDataset(dataset);
+
+    const n_data = llama.datasetSize(dataset);
+    logger.info("Dataset created: {d} training examples", .{n_data});
+
+    if (n_data == 0) {
+        return error.EmptyDataset;
+    }
+
+    // Step 6: Create result trackers for train and validation
+    logger.info("Initializing result trackers...", .{});
+    const result_train = try llama.createOptResult();
+    defer llama.freeOptResult(result_train);
+
+    const result_eval = try llama.createOptResult();
+    defer llama.freeOptResult(result_eval);
