+/// Learn from a git repository by extracting code patterns
+fn learnFromRepo(
+    allocator: std.mem.Allocator,
+    repo_path: []const u8,
+    examples: *std.ArrayList(TrainingExample),
+) !void {
+    // Scan repo for source files
+    var dir = try std.fs.cwd().openDir(repo_path, .{ .iterate = true });
+    defer dir.close();
+
+    var walker = try dir.walk(allocator);
+    defer walker.deinit();
+
+    while (try walker.next()) |entry| {
+        if (entry.kind != .file) continue;
+
+        // Only process code files (Zig for now)
+        if (!std.mem.endsWith(u8, entry.basename, ".zig")) continue;
+
+        // Skip build artifacts and vendor directories
+        if (std.mem.indexOf(u8, entry.path, "zig-cache") != null) continue;
+        if (std.mem.indexOf(u8, entry.path, "zig-out") != null) continue;
+        if (std.mem.indexOf(u8, entry.path, "vendor") != null) continue;
+
+        // Read file
+        const file_path = try std.fs.path.join(allocator, &[_][]const u8{
+            repo_path,
+            entry.path,
+        });
+        defer allocator.free(file_path);
+
+        const content = try std.fs.cwd().readFileAlloc(allocator, file_path, 10 * 1024 * 1024);
+        defer allocator.free(content);
