+/// Extract code patterns (functions, structs) from source code
+fn extractCodePatterns(
+    allocator: std.mem.Allocator,
+    source: []const u8,
+    filename: []const u8,
+    examples: *std.ArrayList(TrainingExample),
+) !void {
+    // Simple pattern extraction: find function definitions
+    // Format: "pub fn name(...) ... { ... }"
+
+    var lines = std.mem.splitScalar(u8, source, '\n');
+    var current_function = try std.ArrayList(u8).initCapacity(allocator, 0);
+    defer current_function.deinit(allocator);
+
+    var in_function = false;
+    var brace_depth: u32 = 0;
+
+    while (lines.next()) |line| {
+        const trimmed = std.mem.trim(u8, line, " \t");
+
+        // Check if this is a function declaration
+        if (std.mem.indexOf(u8, trimmed, "pub fn ") != null or
+            std.mem.indexOf(u8, trimmed, "fn ") != null)
+        {
+            in_function = true;
+            try current_function.appendSlice(allocator, line);
+            try current_function.append(allocator, '\n');
+
+            // Count braces in this line
+            for (line) |c| {
+                if (c == '{') brace_depth += 1;
+                if (c == '}') {
+                    if (brace_depth > 0) brace_depth -= 1;
+                }
+            }
+            continue;
+        }
+
+        if (in_function) {
+            try current_function.appendSlice(allocator, line);
+            try current_function.append(allocator, '\n');
+
+            // Count braces
+            for (line) |c| {
+                if (c == '{') brace_depth += 1;
+                if (c == '}') {
+                    if (brace_depth > 0) brace_depth -= 1;
+                }
+            }
+
+            // Function complete when braces balanced
+            if (brace_depth == 0) {
+                // Save this function as a training example
+                const text = try std.fmt.allocPrint(
+                    allocator,
+                    "// From {s}\n{s}",
+                    .{ filename, current_function.items },
+                );
+
+                try examples.append(allocator, .{ .text = text });
+
+                // Reset for next function
+                current_function.clearRetainingCapacity();
+                in_function = false;
+            }
+        }
+    }
+}

