+/// Cache system prompt during build for instant startup
+fn cacheSystemPrompt(allocator: std.mem.Allocator, model_path: []const u8, system_prompt: []const u8) !void {
+    const snapshot_mod = @import("snapshot.zig");
+
+    std.debug.print("Caching system prompt for instant startup...\n", .{});
+
+    // Load optimization profile
+    const prof = try optimizer.loadOptimizedProfile(allocator, model_path);
+
+    // Load model temporarily
+    var model = try llama.Model.load(model_path, .{
+        .n_gpu_layers = prof.optimal_config.n_gpu_layers,
+    });
+    defer model.deinit();
+
+    var ctx = try llama.Context.init(&model, .{
+        .n_ctx = prof.optimal_config.n_ctx,
+        .n_batch = @min(prof.optimal_config.n_ctx, 512),
+    });
+    defer ctx.deinit();
+
+    // Tokenize and process system prompt
+    const tokens = try llama.tokenize(&model, system_prompt, true);
+    // Note: tokens is a slice of stack memory from tokenize(), don't free it
+
+    // Process tokens through the context to populate KV cache
+    var batch = c.llama_batch_init(@intCast(tokens.len), 0, 1);
+    defer c.llama_batch_free(batch);
+
+    for (0..tokens.len) |i| {
+        batch.token[i] = tokens[i];
+        batch.pos[i] = @intCast(i);
+        batch.n_seq_id[i] = 1;
+        batch.seq_id[i][0] = 0;
+        batch.logits[i] = 0;
+    }
+    batch.logits[tokens.len - 1] = 1; // Enable logits for last token
+    batch.n_tokens = @intCast(tokens.len);
+
+    if (c.llama_decode(ctx.handle, batch) != 0) {
+        return error.DecodeFailed;
+    }
+
+    // Save KV cache using existing snapshot infrastructure
+    try snapshot_mod.saveSystemPromptCache(allocator, &ctx, &model, system_prompt, tokens);
+
+    std.debug.print("✓ System prompt cached (instant restore on run)\n", .{});
+}
