+fn autoDetectLoraAdapter(allocator: std.mem.Allocator, model_path: []const u8) !?AdapterDetectionResult {
+    // Priority 1: Check for auto-trained adapter for this specific model
+    const home = std.posix.getenv("HOME") orelse return autoDetectManualAdapter(allocator);
+
+    // Load model temporarily to get hash
