+        logger.debug("Failed to load model for hash", .{});
+        return autoDetectManualAdapter(allocator);
+    };
+    defer model.deinit();
+
+    const model_hash_val = model.getHash();
+    const auto_adapter_path = try std.fmt.allocPrint(allocator,
+        "{s}/.cache/zell/lora/{x}_auto.lora", .{ home, model_hash_val });
+    defer allocator.free(auto_adapter_path);
+
+    // Check if auto-trained adapter exists
+    std.fs.cwd().access(auto_adapter_path, .{}) catch {
+        // No auto-adapter, fall back to manual detection
+        return autoDetectManualAdapter(allocator);
+    };
+
+    // Auto-adapter found!
+    std.debug.print("🧠 Auto-learned adapter detected\n", .{});
+    const path = try allocator.dupe(u8, auto_adapter_path);
+    const id = try std.fmt.allocPrint(allocator, "{x}_auto", .{model_hash_val});
+    return .{ .path = path, .id = id };
+}
