+/// Fallback: Scan for manual .lora files in current directory and cache
+fn autoDetectManualAdapter(allocator: std.mem.Allocator) !?AdapterDetectionResult {
+    var found_adapters: std.ArrayListUnmanaged([]const u8) = .empty;
+    defer {
+        for (found_adapters.items) |path| allocator.free(path);
+        found_adapters.deinit(allocator);
+    }
+
+    // 1. Scan current directory for .lora files
+    var cwd_dir = std.fs.cwd().openDir(".", .{ .iterate = true }) catch |err| {
+        logger.debug("Could not open current directory: {}", .{err});
+        return null;
+    };
+    defer cwd_dir.close();
+
+    var cwd_iter = cwd_dir.iterate();
+    while (try cwd_iter.next()) |entry| {
+        if (entry.kind == .file and std.mem.endsWith(u8, entry.name, ".lora")) {
+            const path = try std.fmt.allocPrint(allocator, "./{s}", .{entry.name});
+            try found_adapters.append(allocator, path);
+        }
+    }
+
+    // 2. If none found in CWD, scan ~/.cache/zell/lora/ (exclude _auto.lora files)
+    if (found_adapters.items.len == 0) {
+        const home = std.posix.getenv("HOME") orelse return null;
+        const cache_path = try std.fmt.allocPrint(allocator, "{s}/.cache/zell/lora", .{home});
+        defer allocator.free(cache_path);
+
+        var cache_dir = std.fs.cwd().openDir(cache_path, .{ .iterate = true }) catch |err| {
+            logger.debug("Could not open cache directory {s}: {}", .{ cache_path, err });
+            return null;
+        };
+        defer cache_dir.close();
+
+        var cache_iter = cache_dir.iterate();
+        while (try cache_iter.next()) |entry| {
+            if (entry.kind == .file and std.mem.endsWith(u8, entry.name, ".lora")) {
+                // Skip auto-trained adapters
+                if (std.mem.endsWith(u8, entry.name, "_auto.lora")) continue;
+
+                const path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ cache_path, entry.name });
+                try found_adapters.append(allocator, path);
+            }
+        }
+    }
+
+    // 3. Handle results
+    if (found_adapters.items.len == 0) {
+        return null; // No adapters found
+    } else if (found_adapters.items.len == 1) {
+        const path = try allocator.dupe(u8, found_adapters.items[0]);
+        const basename = std.fs.path.basename(path);
+        const id = std.fs.path.stem(basename);
+        return .{ .path = path, .id = id };
+    } else {
+        // Multiple adapters - ambiguous
+        std.debug.print("⚠ Multiple LoRA adapters found:\n", .{});
+        for (found_adapters.items) |path| {
+            std.debug.print("  - {s}\n", .{std.fs.path.basename(path)});
+        }
+        std.debug.print("  Skipping adapter (ambiguous). Keep only one .lora file.\n", .{});
+        return null;
+    }
+}
